<?php

$path = __DIR__.'/../resources/views/comercio/dashboard.blade.php';
$content = file_get_contents($path);

if ($content === false) {
    fwrite(STDERR, "ERROR: No se pudo leer dashboard.blade.php\n");
    exit(1);
}

$buttonPattern = '~<button\b[^>]*(?:disabled[^>]*)?>\s*Branding\s*</button>~s';

$buttonReplacement = <<<'BLADE'
<button
                type="button"
                class="commerce-admin__tab { ($activeTab ?? 'usuarios') === 'branding' ? 'is-active' : '' }"
                data-commerce-tab-button="branding"
                aria-pressed="{ ($activeTab ?? 'usuarios') === 'branding' ? 'true' : 'false' }"
            >
                Branding
            </button>
BLADE;

$content = preg_replace(
    $buttonPattern,
    $buttonReplacement,
    $content,
    1,
    $buttonCount
);

if ($buttonCount !== 1) {
    fwrite(STDERR, "ERROR: No se pudo reemplazar exactamente un boton Branding.\n");
    exit(1);
}

$panelPattern = '~<div\b(?=[^>]*data-commerce-tab-panel="branding")[^>]*>.*</div>\s*(?=</section>\s*@endsection)~s';

$panel = base64_decode('', true);

if ($panel === false) {
    fwrite(STDERR, "ERROR: No se pudo decodificar el panel nuevo.\n");
    exit(1);
}

$content = preg_replace(
    $panelPattern,
    $panel,
    $content,
    1,
    $panelCount
);

if ($panelCount !== 1) {
    fwrite(STDERR, "ERROR: No se pudo reemplazar exactamente un panel Branding.\n");
    exit(1);
}

if (file_put_contents($path, $content) === false) {
    fwrite(STDERR, "ERROR: No se pudo guardar dashboard.blade.php\n");
    exit(1);
}

echo "OK: Boton y panel Branding reemplazados.\n";